class RealTimeDataModel {
  constructor() {
    this.users = new Map();
    this.messages = new Map();
    this.messageOrder = [];
  }

  addUser(id, name) {
    this.users.set(id, { id, name });
  }

  addMessage(id, userId, text) {
    this.messages.set(id, { id, userId, text });
    this.messageOrder.push(id);
  }

  getMessagesWithUsernames() {
    return this.messageOrder.map(msgId => {
      const msg = this.messages.get(msgId);
      const user = this.users.get(msg.userId);
      return { text: msg.text, userName: user ? user.name : 'Unknown' };
    });
  }
}

// Usage:
const model = new RealTimeDataModel();
model.addUser(1, 'Alice');
model.addUser(2, 'Bob');

model.addMessage(100, 1, 'Hi!');
model.addMessage(101, 2, 'Hello!');

console.log(model.getMessagesWithUsernames());

function Animal(name) {
  this.name = name;
}

Animal.prototype.speak = function() {
  console.log(this.name + ' makes a noise.');
};

function Dog(name) {
  Animal.call(this, name); // Call parent constructor
}

Dog.prototype = Object.create(Animal.prototype); // Inherit from Animal
Dog.prototype.constructor = Dog; // Fix constructor pointer

Dog.prototype.speak = function() {
  console.log(this.name + ' barks.');
};

const myDog = new Dog('Rex');
myDog.speak(); // Output: Rex barks.

function Cat(name) {
  Animal.call(this, name);
}

Cat.prototype = Object.create(Animal.prototype);
// Missing: Cat.prototype.constructor = Cat;

const myCat = new Cat('Whiskers');
console.log(myCat.constructor === Cat); // false
console.log(myCat.constructor === Animal); // true

function Bird(name) {
  Animal.call(this, name);
}

// Incorrect inheritance setup - this breaks the prototype chain
Bird.prototype = Animal.prototype;

const myBird = new Bird('Tweety');
myBird.speak(); // Works, but prototype chain shared with Animal

Bird.prototype.fly = function() {
  console.log(this.name + ' flies.');
};

const anotherAnimal = new Animal('Generic');
anotherAnimal.fly(); // Error! fly is not a function

